269:// The MCP server module is used by the session provider to attach tools
270:// to sessions via --mcp-config, and can be imported directly for
271:// testing or custom integrations.
273:export { createMcpServer, startMcpHttpServer } from './mcp-server.ts';
274:export type { McpHttpHandle } from './mcp-server.ts';
276:// ── Spawn helpers ────────────────────────────────────────────────────
278:/** Parsed result from stream-json output. @internal */
279:export interface StreamJsonResult {
280:  exitCode: number;
281:  transcript: Record<string, unknown>[];
282:  costUsd?: number;
283:  tokenUsage?: {
284:    inputTokens: number;
285:    outputTokens: number;
286:    cacheReadTokens?: number;
287:    cacheWriteTokens?: number;
288:  };
289:  providerSessionId?: string;
290:}
