1:/**
2: * The Animator — session launch and telemetry recording apparatus.
3: *
4: * Two API levels:
5: * - summon() — high-level: composes context via The Loom, then launches.
6: * - animate() — low-level: takes a pre-composed AnimaWeave + prompt.
7: *
8: * See: docs/specification.md (animator)
9: */
11:import type { Plugin, StartupContext } from '@shardworks/nexus-core';
12:import { guild, generateId } from '@shardworks/nexus-core';
13:import type { StacksApi, Book } from '@shardworks/stacks-apparatus';
15:import type { LoomApi } from '@shardworks/loom-apparatus';
17:import type {
18:  AnimatorApi,
19:  AnimateHandle,
20:  AnimatorConfig,
21:  AnimateRequest,
22:  SummonRequest,
23:  SessionResult,
24:  SessionChunk,
25:  SessionDoc,
26:  TranscriptDoc,
27:  TranscriptMessage,
28:  AnimatorSessionProvider,
29:  SessionProviderConfig,
30:  SessionProviderResult,
31:} from './types.ts';
33:import { sessionList, sessionShow, summon as summonTool } from './tools/index.ts';
35:// ── Core logic ───────────────────────────────────────────────────────
37:/**
38: * Resolve the session provider apparatus.
39: *
40: * Looks up the provider by plugin id from guild config. The provider is
41: * an apparatus whose `provides` implements AnimatorSessionProvider.
42: * Arbor throws immediately if the plugin isn't loaded or has no provides.
43: */
44:function resolveProvider(config: AnimatorConfig): AnimatorSessionProvider {
45:  const pluginId = config.sessionProvider ?? 'claude-code';
46:  return guild().apparatus<AnimatorSessionProvider>(pluginId);
47:}
49:/**
50: * Resolve the model from guild settings.
51: */
52:function resolveModel(): string {
53:  const g = guild();
54:  const guildConfig = g.guildConfig();
55:  return guildConfig.settings?.model ?? 'sonnet';
56:}
58:/**
59: * Build the provider config from an AnimateRequest.
60: *
61: * The system prompt comes from the AnimaWeave (composed by The Loom).
62: * The work prompt comes from the request directly (bypasses The Loom).
63: * The streaming flag is passed through for the provider to honor (or ignore).
64: */
65:function buildProviderConfig(
66:  request: AnimateRequest,
67:  model: string,
68:): SessionProviderConfig {
69:  return {
70:    systemPrompt: request.context.systemPrompt,
71:    initialPrompt: request.prompt,
72:    model,
73:    conversationId: request.conversationId,
74:    cwd: request.cwd,
75:    streaming: request.streaming,
76:    tools: request.context.tools,
77:    environment: { ...request.context.environment, ...request.environment },
78:  };
79:}
81:/**
82: * Build a SessionResult from provider output and session metadata.
83: */
84:function buildSessionResult(
85:  id: string,
86:  startedAt: string,
87:  providerName: string,
88:  providerResult: SessionProviderResult,
89:  request: AnimateRequest,
90:): SessionResult {
91:  const endedAt = new Date().toISOString();
92:  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
94:  return {
95:    id,
96:    status: providerResult.status,
97:    startedAt,
98:    endedAt,
99:    durationMs,
100:    provider: providerName,
101:    exitCode: providerResult.exitCode,
102:    error: providerResult.error,
103:    conversationId: request.conversationId,
104:    providerSessionId: providerResult.providerSessionId,
105:    tokenUsage: providerResult.tokenUsage,
106:    costUsd: providerResult.costUsd,
107:    metadata: request.metadata,
108:    output: providerResult.output,
109:  };
110:}
112:/**
113: * Build a failed SessionResult when the provider throws.
114: */
115:function buildFailedResult(
116:  id: string,
117:  startedAt: string,
118:  providerName: string,
119:  error: unknown,
120:  request: AnimateRequest,
121:): SessionResult {
122:  const endedAt = new Date().toISOString();
123:  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
124:  const errorMessage = error instanceof Error ? error.message : String(error);
126:  return {
127:    id,
128:    status: 'failed',
129:    startedAt,
130:    endedAt,
131:    durationMs,
132:    provider: providerName,
133:    exitCode: 1,
134:    error: errorMessage,
135:    conversationId: request.conversationId,
136:    metadata: request.metadata,
137:  };
138:}
140:/**
141: * Convert a SessionResult to a SessionDoc for Stacks storage.
142: */
143:function toSessionDoc(result: SessionResult): SessionDoc {
144:  return {
145:    id: result.id,
146:    status: result.status,
147:    startedAt: result.startedAt,
148:    endedAt: result.endedAt,
149:    durationMs: result.durationMs,
150:    provider: result.provider,
151:    exitCode: result.exitCode,
152:    error: result.error,
153:    conversationId: result.conversationId,
154:    providerSessionId: result.providerSessionId,
155:    tokenUsage: result.tokenUsage,
156:    costUsd: result.costUsd,
157:    metadata: result.metadata,
158:    output: result.output,
159:  };
160:}
162:/**
163: * Record a session result to The Stacks (sessions + transcripts books).
164: *
165: * Errors are logged but never propagated — session data loss is
166: * preferable to masking the original failure. See § Error Handling Contract.
167: */
168:async function recordSession(
169:  sessions: Book<SessionDoc>,
170:  transcripts: Book<TranscriptDoc>,
171:  result: SessionResult,
172:  transcript: TranscriptMessage[] | undefined,
173:): Promise<void> {
174:  try {
175:    await sessions.put(toSessionDoc(result));
176:  } catch (err) {
177:    console.warn(
178:      `[animator] Failed to record session ${result.id}: ${err instanceof Error ? err.message : err}`,
179:    );
180:  }
182:  if (transcript && transcript.length > 0) {
183:    try {
184:      await transcripts.put({ id: result.id, messages: transcript });
185:    } catch (err) {
186:      console.warn(
187:        `[animator] Failed to record transcript for ${result.id}: ${err instanceof Error ? err.message : err}`,
188:      );
189:    }
190:  }
191:}
193:/**
194: * Write the initial 'running' session record to The Stacks.
195: */
196:async function recordRunning(
197:  sessions: Book<SessionDoc>,
198:  id: string,
199:  startedAt: string,
200:  providerName: string,
201:  request: AnimateRequest,
202:): Promise<void> {
203:  try {
204:    await sessions.put({
205:      id,
206:      status: 'running',
207:      startedAt,
208:      provider: providerName,
209:      conversationId: request.conversationId,
210:      metadata: request.metadata,
211:    });
212:  } catch (err) {
213:    console.warn(
214:      `[animator] Failed to write initial session record ${id}: ${err instanceof Error ? err.message : err}`,
215:    );
216:  }
217:}
219:// ── Apparatus factory ────────────────────────────────────────────────
221:/**
222: * Create the Animator apparatus plugin.
223: *
224: * Returns a Plugin with:
225: * - `requires: ['stacks']` — records session results
226: * - `provides: AnimatorApi` — the session launch API
227: * - `supportKit` — contributes `sessions` book + inspection tools
228: */
229:export function createAnimator(): Plugin {
230:  let config: AnimatorConfig = {};
231:  let sessions: Book<SessionDoc>;
232:  let transcripts: Book<TranscriptDoc>;
234:  const api: AnimatorApi = {
235:    summon(request: SummonRequest): AnimateHandle {
236:      // Resolve The Loom at call time — not a startup dependency.
237:      // This allows the Animator to start without the Loom installed;
238:      // only summon() requires it.
239:      let loom: LoomApi;
240:      try {
241:        loom = guild().apparatus<LoomApi>('loom');
242:      } catch {
243:        throw new Error(
244:          'summon() requires The Loom apparatus to be installed. ' +
245:          'Use animate() directly if you want to provide a pre-composed AnimaWeave.',
246:        );
247:      }
249:      // Generate session id up front so it's available on the handle
250:      // immediately — before the Loom weave or session launch resolves.
251:      const sessionId = generateId('ses', 4);
253:      // We need to weave context before we can animate, but summon()
254:      // must return synchronously. Wrap the async Loom call and the
255:      // animate delegation into a single deferred flow.
256:      const deferred = (async () => {
257:        // Compose identity context via The Loom.
258:        // The Loom owns system prompt composition — it produces the system
259:        // prompt from the anima's identity layers (role instructions,
260:        // curriculum, temperament, charter). MVP: returns empty (no
261:        // systemPrompt); the session runs without one until the Loom
262:        // gains composition logic. The work prompt bypasses the Loom.
263:        const context = await loom.weave({
264:          role: request.role,
265:        });
267:        // Merge caller metadata with auto-generated summon metadata
268:        const metadata: Record<string, unknown> = {
269:          trigger: 'summon',
270:          ...(request.role ? { role: request.role } : {}),
271:          ...request.metadata,
272:        };

