1:/**
2: * MCP Tool Server — serves guild tools as typed MCP tools during anima sessions.
3: *
4: * Two entry points:
5: *
6: * 1. **`createMcpServer(tools)`** — library function. Takes an array of
7: *    ToolDefinitions (already resolved by the Instrumentarium) and returns
8: *    a configured McpServer.
9: *
10: * 2. **`startMcpHttpServer(tools)`** — starts an in-process HTTP server
11: *    serving the MCP tool set via Streamable HTTP on an ephemeral localhost
12: *    port. Returns a handle with the URL (for --mcp-config) and a close()
13: *    function for cleanup.
14: *
15: * The MCP server is one-per-session. The claude-code provider owns the
16: * lifecycle — starts before the Claude process, stops after it exits.
17: *
18: * See: docs/architecture/apparatus/claude-code.md
19: */
21:import http from 'node:http';
23:import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
24:import { SSEServerTransport } from '@modelcontextprotocol/sdk/server/sse.js';
25:import { VERSION } from '@shardworks/nexus-core';
26:import type { ToolDefinition } from '@shardworks/tools-apparatus';
28:// ── Public types ────────────────────────────────────────────────────────
30:/**
31: * Handle returned by startMcpHttpServer().
32: *
33: * Provides the URL for --mcp-config and a close() function for cleanup.
34: */
35:export interface McpHttpHandle {
36:  /** URL for --mcp-config (e.g. "http://127.0.0.1:PORT/mcp"). */
37:  url: string;
38:  /** Shut down the HTTP server and MCP transport. */
39:  close(): Promise<void>;
40:}
42:// ── Library API ─────────────────────────────────────────────────────────
44:/**
45: * Create and configure an MCP server with the given tools.
46: *
47: * Each tool's Zod param schema is registered directly with the MCP SDK
48: * (which handles JSON Schema conversion). The handler is wrapped to
49: * validate params via Zod and format the result as MCP tool output.
50: *
51: * Tools with `callableBy` set that does not include `'anima'` are
52: * filtered out. Tools without `callableBy` are included (available
53: * to all callers by default).
54: */
55:export async function createMcpServer(tools: ToolDefinition[]): Promise<McpServer> {
56:  const server = new McpServer({
57:    name: 'nexus-guild',
58:    version: VERSION,
59:  });
61:  for (const def of tools) {
62:    // Filter by callableBy — only serve tools callable by animas.
63:    // Tools with no callableBy default to all callers (available everywhere).
64:    if (def.callableBy && !def.callableBy.includes('anima')) {
65:      continue;
66:    }
68:    server.tool(
69:      def.name,
70:      def.description,
71:      def.params.shape,
72:      async (params) => {
73:        try {
74:          const validated = def.params.parse(params);
75:          const result = await def.handler(validated);
77:          return {
78:            content: [{
79:              type: 'text' as const,
80:              text: typeof result === 'string' ? result : JSON.stringify(result, null, 2),
81:            }],
82:          };
83:        } catch (err) {
84:          const message = err instanceof Error ? err.message : String(err);
85:          return {
86:            content: [{ type: 'text' as const, text: `Error: ${message}` }],
87:            isError: true,
88:          };
89:        }
90:      },
91:    );
92:  }
94:  return server;
95:}
97:// ── HTTP Server ─────────────────────────────────────────────────────────
99:/**
100: * Start an in-process HTTP server serving the MCP tool set via SSE.
101: *
102: * Uses the MCP SDK's SSE transport: the client GETs /sse to establish
103: * the event stream, then POSTs messages to /message. Claude Code's
104: * --mcp-config expects `type: "sse"` for HTTP-based MCP servers.
105: *
106: * The server binds to 127.0.0.1 only — not network-accessible.
107: *
108: * Returns a handle with the URL (for --mcp-config) and a close() function.
109: * The caller is responsible for calling close() after the session exits.
110: *
111: * Each session gets its own server instance. Concurrent sessions get
112: * independent servers on different ports.
113: */
114:export async function startMcpHttpServer(tools: ToolDefinition[]): Promise<McpHttpHandle> {
115:  const mcpServer = await createMcpServer(tools);
117:  // SSE transport: the client GETs /sse, the transport tells it to POST
118:  // messages to /message. One transport per connection (single-session).
119:  let transport: SSEServerTransport | null = null;
121:  const httpServer = http.createServer(async (req, res) => {
122:    try {
123:      if (req.method === 'GET' && req.url === '/sse') {
124:        // New SSE connection — create transport bound to this response.
125:        transport = new SSEServerTransport('/message', res);
126:        await mcpServer.connect(transport);
127:      } else if (req.method === 'POST' && req.url?.startsWith('/message')) {
128:        if (!transport) {
129:          res.writeHead(400).end('No active SSE connection');
130:          return;
131:        }
132:        await transport.handlePostMessage(req, res);
133:      } else {
134:        res.writeHead(404).end('Not found');
135:      }
136:    } catch {
137:      if (!res.headersSent) {
138:        res.writeHead(500).end('Internal Server Error');
139:      }
140:    }
141:  });
143:  // Listen on ephemeral port, localhost only.
144:  await new Promise<void>((resolve) => {
145:    httpServer.listen(0, '127.0.0.1', resolve);
146:  });
148:  const addr = httpServer.address();
149:  if (!addr || typeof addr === 'string') {
150:    throw new Error('Failed to get server address');
151:  }
153:  const url = `http://127.0.0.1:${addr.port}/sse`;
155:  return {
156:    url,
157:    async close() {
158:      if (transport) {
159:        await transport.close();
160:      }
161:      await new Promise<void>((resolve, reject) => {
162:        httpServer.close((err) => (err ? reject(err) : resolve()));
163:      });
164:    },
165:  };
166:}

