297: *
298: * @internal Exported for testing only.
299: */
300:export function parseStreamJsonMessage(
301:  msg: Record<string, unknown>,
302:  acc: {
303:    transcript: Record<string, unknown>[];
304:    costUsd?: number;
305:    tokenUsage?: StreamJsonResult['tokenUsage'];
306:    providerSessionId?: string;
307:  },
308:): SessionChunk[] {
309:  const chunks: SessionChunk[] = [];
311:  if (msg.type === 'assistant') {
312:    acc.transcript.push(msg);
314:    const message = msg.message as Record<string, unknown> | undefined;
315:    if (message) {
316:      const content = message.content as Array<Record<string, unknown>> | undefined;
317:      if (content) {
318:        for (const block of content) {
319:          if (block.type === 'text' && typeof block.text === 'string') {
320:            process.stderr.write(block.text);
321:            chunks.push({ type: 'text', text: block.text });
322:          } else if (block.type === 'tool_use' && typeof block.name === 'string') {
323:            chunks.push({ type: 'tool_use', tool: block.name });
324:          }
325:        }
326:      }
327:    }
328:  } else if (msg.type === 'user') {
329:    acc.transcript.push(msg);
331:    const content = (msg as Record<string, unknown>).content as Array<Record<string, unknown>> | undefined;
332:    if (content) {
333:      for (const block of content) {
334:        if (block.type === 'tool_result' && typeof block.tool_use_id === 'string') {
335:          chunks.push({ type: 'tool_result', tool: String(block.tool_use_id) });
336:        }
337:      }
338:    }
339:  } else if (msg.type === 'result') {
340:    acc.costUsd = typeof msg.total_cost_usd === 'number' ? msg.total_cost_usd : undefined;
341:    acc.providerSessionId = typeof msg.session_id === 'string' ? msg.session_id : undefined;
343:    const usage = msg.usage as Record<string, unknown> | undefined;
344:    if (usage) {
345:      acc.tokenUsage = {
346:        inputTokens: (typeof usage.input_tokens === 'number' ? usage.input_tokens : 0),
347:        outputTokens: (typeof usage.output_tokens === 'number' ? usage.output_tokens : 0),
348:        cacheReadTokens: typeof usage.cache_read_input_tokens === 'number'
349:          ? usage.cache_read_input_tokens : undefined,
350:        cacheWriteTokens: typeof usage.cache_creation_input_tokens === 'number'
351:          ? usage.cache_creation_input_tokens : undefined,
352:      };
353:    }
354:  }
356:  return chunks;
357:}
359:/**
360: * Process NDJSON buffer, calling handler for each complete line.
361: * Returns the remaining incomplete buffer.
362: *
363: * @internal Exported for testing only.
364: */
365:export function processNdjsonBuffer(
366:  buffer: string,
367:  handler: (msg: Record<string, unknown>) => void,
368:): string {
369:  let newlineIdx: number;
370:  while ((newlineIdx = buffer.indexOf('\n')) !== -1) {
371:    const line = buffer.slice(0, newlineIdx).trim();
372:    buffer = buffer.slice(newlineIdx + 1);
374:    if (!line) continue;
376:    try {
377:      const msg = JSON.parse(line) as Record<string, unknown>;
378:      handler(msg);
379:    } catch {
380:      // Non-JSON line — ignore
381:    }
382:  }
383:  return buffer;
384:}
386:/**
387: * Spawn Claude in autonomous mode with --output-format stream-json.
388: *
389: * Captures stdout (NDJSON lines), parses each line to extract:
390: * - assistant messages → transcript
391: * - result message → cost, token usage, session ID
392: *
393: * Forwards assistant text content to stderr so it's visible during execution.
394: */
395:function spawnClaudeStreamJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): Promise<StreamJsonResult> {
396:  return new Promise((resolve, reject) => {
397:    const proc = spawn('claude', args, {
398:      cwd,
399:      stdio: ['pipe', 'pipe', 'inherit'],
400:      env: { ...process.env, ...env },
401:    });
403:    // Pipe prompt via stdin (--print - reads from stdin)
404:    if (stdinData !== undefined) {
405:      proc.stdin!.write(stdinData);
406:      proc.stdin!.end();
407:    }
409:    const acc: {
410:      transcript: Record<string, unknown>[];
411:      costUsd?: number;
412:      tokenUsage?: StreamJsonResult['tokenUsage'];
413:      providerSessionId?: string;
414:    } = { transcript: [] };
416:    let buffer = '';
