1:/**
2: * Tests for the MCP server module.
3: *
4: * Exercises createMcpServer() with ToolDefinition arrays to verify
5: * tool registration, callableBy filtering, and error handling.
6: * Tests startMcpHttpServer() for HTTP server lifecycle and connectivity.
7: */
9:import { describe, it } from 'node:test';
10:import assert from 'node:assert/strict';
11:import { z } from 'zod';
13:import { tool } from '@shardworks/tools-apparatus';
15:import { createMcpServer, startMcpHttpServer } from './mcp-server.ts';
17:// ── Test helpers ────────────────────────────────────────────────────────
19:function makeTool(overrides: {
20:  name?: string;
21:  description?: string;
22:  permission?: string;
23:  callableBy?: ('cli' | 'anima' | 'library')[];
24:  handler?: () => unknown;
25:} = {}) {
26:  return tool({
27:    name: overrides.name ?? 'test-tool',
28:    description: overrides.description ?? 'A test tool',
29:    params: { input: z.string().describe('Test input') },
30:    handler: overrides.handler ?? (async () => ({ ok: true })),
31:    ...(overrides.permission !== undefined ? { permission: overrides.permission } : {}),
32:    ...(overrides.callableBy !== undefined ? { callableBy: overrides.callableBy } : {}),
33:  });
34:}
36:// ── createMcpServer ─────────────────────────────────────────────────────
38:describe('createMcpServer()', () => {
39:  it('returns an McpServer instance with no tools', async () => {
40:    const server = await createMcpServer([]);
41:    assert.ok(server, 'should return a server object');
42:  });
44:  it('accepts an array of ToolDefinitions', async () => {
45:    const tools = [
46:      makeTool({ name: 'tool-a', description: 'First tool' }),
47:      makeTool({ name: 'tool-b', description: 'Second tool' }),
48:    ];
50:    const server = await createMcpServer(tools);
51:    assert.ok(server, 'should return a server with tools registered');
52:  });
54:  it('filters out tools not callable by animas', async () => {
55:    const tools = [
56:      makeTool({ name: 'cli-only', callableBy: ['cli'] }),
57:      makeTool({ name: 'anima-ok', callableBy: ['anima'] }),
58:      makeTool({ name: 'both', callableBy: ['cli', 'anima'] }),
59:      makeTool({ name: 'no-restriction' }), // no callableBy → available to everyone
60:    ];
62:    // createMcpServer filters internally — it should not throw
63:    const server = await createMcpServer(tools);
64:    assert.ok(server, 'should handle mixed callableBy tools');
65:  });
67:  it('handles tools with permission fields', async () => {
68:    const tools = [
69:      makeTool({ name: 'read-tool', permission: 'read' }),
70:      makeTool({ name: 'write-tool', permission: 'write' }),
71:      makeTool({ name: 'no-perm' }),
72:    ];
74:    // Permission is not checked by createMcpServer — it registers all tools.
75:    // Permission gating happens upstream in the Instrumentarium.
76:    const server = await createMcpServer(tools);
77:    assert.ok(server, 'should register tools regardless of permission field');
78:  });
79:});
81:// ── startMcpHttpServer ──────────────────────────────────────────────────
83:describe('startMcpHttpServer()', () => {
84:  it('starts an HTTP server and returns a handle with URL and close', async () => {
85:    const tools = [makeTool({ name: 'test-tool' })];
86:    const handle = await startMcpHttpServer(tools);
88:    try {
89:      assert.ok(handle.url, 'should have a URL');
90:      assert.match(handle.url, /^http:\/\/127\.0\.0\.1:\d+\/sse$/, 'URL should be localhost with /sse endpoint');
91:      assert.equal(typeof handle.close, 'function', 'should have a close function');
92:    } finally {
93:      await handle.close();
94:    }
95:  });
97:  it('listens on an ephemeral port', async () => {
98:    const handle = await startMcpHttpServer([makeTool({ name: 'tool-a' })]);
100:    try {
101:      const port = parseInt(new URL(handle.url).port, 10);
102:      assert.ok(port > 0, 'should bind to a real port');
103:      assert.ok(port < 65536, 'port should be in valid range');
104:    } finally {
105:      await handle.close();
106:    }
107:  });
109:  it('responds to HTTP requests on the MCP endpoint', async () => {
110:    const tools = [makeTool({ name: 'ping-tool' })];
111:    const handle = await startMcpHttpServer(tools);
113:    try {
114:      // Send a basic HTTP request to the MCP endpoint.
115:      // The MCP protocol expects JSON-RPC — a plain GET should get a
116:      // response (likely 405 or similar) rather than a connection error.
117:      const res = await fetch(handle.url, { method: 'GET' });
118:      // Any HTTP response means the server is listening and reachable.
119:      assert.ok(res.status > 0, 'should get an HTTP response');
120:    } finally {
121:      await handle.close();
122:    }
123:  });
125:  it('can start multiple servers on different ports', async () => {
126:    const handle1 = await startMcpHttpServer([makeTool({ name: 'tool-1' })]);
127:    const handle2 = await startMcpHttpServer([makeTool({ name: 'tool-2' })]);
129:    try {
130:      assert.notEqual(handle1.url, handle2.url, 'should bind to different ports');
131:    } finally {
132:      await handle1.close();
133:      await handle2.close();
134:    }
135:  });
137:  it('close() shuts down the server', async () => {
138:    const handle = await startMcpHttpServer([makeTool({ name: 'tool-a' })]);
139:    await handle.close();
141:    // After close, the server should no longer accept connections.
142:    try {
143:      await fetch(handle.url, { method: 'GET' });
144:      assert.fail('should not be reachable after close');
145:    } catch (err) {
146:      // Expected — connection refused or similar network error
147:      assert.ok(err, 'fetch should throw after server is closed');
148:    }
149:  });
151:  it('works with empty tool set', async () => {
152:    const handle = await startMcpHttpServer([]);
153:    try {
154:      assert.ok(handle.url, 'should start even with no tools');
155:    } finally {
156:      await handle.close();
157:    }
158:  });
159:});

