1:/**
2: * Animator tests.
3: *
4: * Uses a fake session provider apparatus and in-memory Stacks backend to
5: * test the full animate() lifecycle without spawning real processes.
6: *
7: * The fake provider is registered as an apparatus in the guild mock,
8: * matching how real providers work (the Animator discovers them via
9: * guild().apparatus(config.sessionProvider)).
10: */
12:import { describe, it, beforeEach, afterEach } from 'node:test';
13:import assert from 'node:assert/strict';
15:import { setGuild, clearGuild } from '@shardworks/nexus-core';
16:import type { Guild } from '@shardworks/nexus-core';
17:import { createStacksApparatus } from '@shardworks/stacks-apparatus';
18:import { MemoryBackend } from '@shardworks/stacks-apparatus/testing';
19:import type { StacksApi } from '@shardworks/stacks-apparatus';
21:import { createLoom } from '@shardworks/loom-apparatus';
22:import type { LoomApi } from '@shardworks/loom-apparatus';
24:import { createAnimator } from './animator.ts';
25:import type {
26:  AnimatorApi,
27:  AnimatorSessionProvider,
28:  SessionProviderConfig,
29:  SessionProviderResult,
30:  SessionChunk,
31:  SessionDoc,
32:  TranscriptDoc,
33:} from './types.ts';
35:// ── Shared empty chunks iterable ─────────────────────────────────────
37:const emptyChunks: AsyncIterable<SessionChunk> = {
38:  [Symbol.asyncIterator]() {
39:    return {
40:      async next() {
41:        return { value: undefined as unknown as SessionChunk, done: true as const };
42:      },
43:    };
44:  },
45:};
47:// ── Fake providers ───────────────────────────────────────────────────
49:function createFakeProvider(
50:  overrides: Partial<SessionProviderResult> = {},
51:): AnimatorSessionProvider {
52:  return {
53:    name: 'fake',
54:    launch(_config: SessionProviderConfig) {
55:      return {
56:        chunks: emptyChunks,
57:        result: Promise.resolve({
58:          status: 'completed' as const,
59:          exitCode: 0,
60:          providerSessionId: 'fake-sess-123',
61:          tokenUsage: {
62:            inputTokens: 1000,
63:            outputTokens: 500,
64:          },
65:          costUsd: 0.05,
66:          ...overrides,
67:        }),
68:      };
69:    },
70:  };
71:}
73:function createStreamingFakeProvider(
74:  streamChunks: SessionChunk[],
75:  overrides: Partial<SessionProviderResult> = {},
76:): AnimatorSessionProvider {
77:  return {
78:    name: 'fake-streaming',
79:    launch(config: SessionProviderConfig) {
80:      if (config.streaming) {
81:        let idx = 0;
82:        const asyncChunks: AsyncIterable<SessionChunk> = {
83:          [Symbol.asyncIterator]() {
84:            return {
85:              async next() {
86:                if (idx < streamChunks.length) {
87:                  return { value: streamChunks[idx++]!, done: false as const };
88:                }
89:                return { value: undefined as unknown as SessionChunk, done: true as const };
90:              },
91:            };
92:          },
93:        };
95:        return {
96:          chunks: asyncChunks,
97:          result: Promise.resolve({
98:            status: 'completed' as const,
99:            exitCode: 0,
100:            providerSessionId: 'fake-stream-sess',
101:            ...overrides,
102:          }),
103:        };
104:      }
106:      // Non-streaming: return empty chunks
107:      return {
108:        chunks: emptyChunks,
109:        result: Promise.resolve({
110:          status: 'completed' as const,
111:          exitCode: 0,
112:          providerSessionId: 'fake-stream-sess',
113:          ...overrides,
114:        }),
115:      };
116:    },
117:  };
118:}
120:function createThrowingProvider(error: Error): AnimatorSessionProvider {
121:  return {
122:    name: 'fake-throwing',
123:    launch() {
124:      return {
125:        chunks: emptyChunks,
126:        result: Promise.reject(error),
127:      };
128:    },
129:  };
130:}
132:// ── Spy provider (captures the config passed to launch) ──────────────
134:function createSpyProvider(): {
135:  provider: AnimatorSessionProvider;
136:  getCapturedConfig: () => SessionProviderConfig | null;
137:} {
138:  let capturedConfig: SessionProviderConfig | null = null;
140:  return {
141:    provider: {
142:      name: 'fake-spy',
143:      launch(config: SessionProviderConfig) {
144:        capturedConfig = config;
145:        return {
146:          chunks: emptyChunks,
147:          result: Promise.resolve({ status: 'completed' as const, exitCode: 0 }),
148:        };
149:      },
150:    },
151:    getCapturedConfig: () => capturedConfig,
152:  };
153:}
155:// ── Test harness ─────────────────────────────────────────────────────
157:let stacks: StacksApi;
158:let animator: AnimatorApi;
159:let memBackendRef: InstanceType<typeof MemoryBackend>;
161:/**
162: * Set up the test environment with a guild mock, in-memory Stacks,
163: * and the Animator apparatus. The provider is registered as an apparatus
164: * that the Animator discovers via guild().apparatus('fake-provider').
165: *
166: * @param opts.installLoom — if true, installs The Loom apparatus (needed for summon() tests)
167: */
168:function setup(
169:  provider: AnimatorSessionProvider = createFakeProvider(),
170:  sessionProviderPluginId = 'fake-provider',
171:  opts: { installLoom?: boolean } = {},
172:) {
173:  memBackendRef = new MemoryBackend();
174:  const memBackend = memBackendRef;
175:  const stacksPlugin = createStacksApparatus(memBackend);
176:  const animatorPlugin = createAnimator();
178:  // Apparatus registry for the guild mock
179:  const apparatusMap = new Map<string, unknown>();
181:  // Register the provider as an apparatus (same as a real guild would)
182:  apparatusMap.set(sessionProviderPluginId, provider);
184:  const fakeGuild: Guild = {
185:    home: '/tmp/fake-guild',
186:    apparatus<T>(name: string): T {
187:      const api = apparatusMap.get(name);
188:      if (!api) throw new Error(`Apparatus "${name}" not installed`);
189:      return api as T;
190:    },
191:    config<T>(pluginId: string): T {
192:      if (pluginId === 'animator') {
193:        return { sessionProvider: sessionProviderPluginId } as T;
194:      }
195:      return {} as T;
196:    },
197:    writeConfig() { /* noop in test */ },
198:    guildConfig() {
199:      return {
200:        name: 'test-guild',
201:        nexus: '0.0.0',
202:        workshops: {},
203:        roles: {},
204:        baseTools: [],
205:        plugins: [],
206:        settings: { model: 'sonnet' },
207:        animator: { sessionProvider: sessionProviderPluginId },
208:      };
209:    },
210:    kits: () => [],
211:    apparatuses: () => [],
212:  };
214:  // Must set guild before starting apparatus that call guild() in start()
215:  setGuild(fakeGuild);
217:  // Optionally install The Loom (needed for summon() tests)
218:  if (opts.installLoom) {
219:    const loomPlugin = createLoom();
220:    const loomApparatus = (loomPlugin as { apparatus: { start: (ctx: unknown) => void; provides: unknown } }).apparatus;
221:    loomApparatus.start({ on: () => {} });
222:    apparatusMap.set('loom', loomApparatus.provides);
223:  }
225:  // Start stacks
226:  const stacksApparatus = (stacksPlugin as { apparatus: { start: (ctx: unknown) => void; provides: unknown } }).apparatus;
227:  stacksApparatus.start({ on: () => {} });
228:  stacks = stacksApparatus.provides as StacksApi;
229:  apparatusMap.set('stacks', stacks);
231:  // Ensure the animator's books are created
232:  memBackend.ensureBook({ ownerId: 'animator', book: 'sessions' }, {
233:    indexes: ['startedAt', 'status', 'conversationId', 'provider'],
234:  });
235:  memBackend.ensureBook({ ownerId: 'animator', book: 'transcripts' }, {
236:    indexes: ['sessionId'],
237:  });
239:  // Start animator
240:  const animatorApparatus = (animatorPlugin as { apparatus: { start: (ctx: unknown) => void; provides: unknown } }).apparatus;
241:  animatorApparatus.start({ on: () => {} });
242:  animator = animatorApparatus.provides as AnimatorApi;
243:}
245:// ── Tests ────────────────────────────────────────────────────────────
247:describe('Animator', () => {
248:  afterEach(() => {
249:    clearGuild();
250:  });
252:  describe('animate()', () => {
253:    beforeEach(() => {
254:      setup();
255:    });
