132:    const looksLikePath = source.startsWith('.') || source.startsWith('/');
133:    const isDirectory = looksLikePath && fs.existsSync(sourceDir) && fs.statSync(sourceDir).isDirectory();
134:    const installType = params.type ?? (isDirectory ? 'link' : 'registry');
136:    // 1. Install the npm package into the guild
137:    let packageName: string;
139:    if (installType === 'link') {
140:      const sourceDir = path.resolve(source);
141:      if (!fs.existsSync(path.join(sourceDir, 'package.json'))) {
142:        throw new Error(`No package.json found in ${sourceDir}. --link requires a directory with a package.json.`);
143:      }
144:      const pkgJson = JSON.parse(fs.readFileSync(path.join(sourceDir, 'package.json'), 'utf-8')) as Record<string, unknown>;
145:      packageName = pkgJson.name as string;
146:      const pm = detectPackageManager(home);
147:      if (pm === 'pnpm') {
148:        pnpm(['add', `link:${sourceDir}`], home);
149:      } else {
150:        npm(['install', '--save', `file:${sourceDir}`], home);
151:      }
152:    } else {
153:      npm(['install', '--save', source], home);
154:      packageName = parsePackageName(source) ?? detectInstalledPackage(home);
156:      const { pkgJson } = readGuildPackageJson(home, packageName);
157:      if (!pkgJson) {
158:        throw new Error(`Package "${packageName}" not found in node_modules after install.`);
159:      }
160:    }
162:    const pluginId = derivePluginId(packageName);
164:    // 2. Update guild.json — add to plugins list
165:    const config = readGuildConfig(home);
167:    if (!config.plugins.includes(pluginId)) {
168:      config.plugins.push(pluginId);
169:    }
171:    writeGuildConfig(home, config);
173:    return `Installed plugin: ${pluginId} (${packageName})`;
174:  },
175:});
177:export const pluginRemove = tool({
178:  name: 'plugin-remove',
179:  description: 'Remove a plugin from the guild',
180:  callableBy: ['cli'],
181:  params: {
182:    name: z.string().describe('Plugin id or package name to remove'),
183:  },
184:  handler: async (params) => {
185:    const { home } = guild();
186:    const config = readGuildConfig(home);
187:    const targetId = params.name.startsWith('@') ? derivePluginId(params.name) : params.name;
189:    if (!config.plugins.includes(targetId)) {
190:      throw new Error(`Plugin "${targetId}" is not installed.`);
191:    }
193:    config.plugins = config.plugins.filter((id) => id !== targetId);
194:    writeGuildConfig(home, config);
196:    const packageName = resolvePackageNameForPluginId(home, targetId);
197:    if (packageName) {
198:      try {
199:        const pm = detectPackageManager(home);
200:        if (pm === 'pnpm') {
201:          pnpm(['remove', packageName], home);
202:        } else {
203:          npm(['uninstall', packageName], home);
204:        }
205:      } catch {
206:        // Don't fail if uninstall fails — guild.json is already updated
207:      }
208:    }
210:    return `Removed plugin: ${targetId}`;
211:  },
212:});
