1:/**
2: * Package resolution utilities for guild-installed npm packages.
3: *
4: * Resolves entry points from the guild's node_modules by reading package.json
5: * exports maps directly. Needed because guild plugins are ESM-only packages
6: * and createRequire() can't resolve their exports.
7: *
8: * Also owns:
9: * - derivePluginId — canonical npm package name → plugin id derivation
10: */
12:import fs from 'node:fs';
13:import path from 'node:path';
15:/**
16: * Derive the guild-facing plugin id from an npm package name.
17: *
18: * Convention:
19: * - `@shardworks/nexus-ledger`      → `nexus-ledger`   (official scope stripped)
20: * - `@shardworks/books-apparatus`   → `books`           (descriptor suffix stripped)
21: * - `@acme/my-plugin`               → `acme/my-plugin`  (third-party: drop @ only)
22: * - `my-relay-kit`                  → `my-relay`        (descriptor suffix stripped)
23: * - `my-plugin`                     → `my-plugin`       (unscoped: unchanged)
24: *
25: * The `@shardworks` scope is the official Nexus namespace — its plugins are
26: * referenced by bare name in guild.json, CLI commands, and config keys.
27: * Third-party scoped packages retain the scope as a prefix (without @) to
28: * prevent collisions between `@acme/foo` and `@other/foo`.
29: *
30: * Descriptor suffixes (`-plugin`, `-apparatus`, `-kit`) are stripped after
31: * scope resolution so that package naming conventions don't leak into ids.
32: */
33:export function derivePluginId(packageName: string): string {
34:  // Step 1: strip scope
35:  let name: string;
36:  if (packageName.startsWith('@shardworks/')) {
37:    name = packageName.slice('@shardworks/'.length);
38:  } else if (packageName.startsWith('@')) {
39:    name = packageName.slice(1); // @acme/foo → acme/foo
40:  } else {
41:    name = packageName;
42:  }
43:  // Step 2: strip descriptor suffix
44:  return name.replace(/-(plugin|apparatus|kit)$/, '');
45:}
47:/**
48: * Read a package.json from the guild's node_modules.
49: * Returns the parsed JSON and version. Falls back gracefully.
50: */
51:export function readGuildPackageJson(
52:  guildRoot: string,
53:  pkgName: string,
54:): { version: string; pkgJson: Record<string, unknown> | null } {
55:  const pkgJsonPath = path.join(guildRoot, 'node_modules', pkgName, 'package.json');
56:  try {
57:    const pkgJson = JSON.parse(fs.readFileSync(pkgJsonPath, 'utf-8')) as Record<string, unknown>;
58:    return { version: (pkgJson.version as string) ?? 'unknown', pkgJson };
59:  } catch {
60:    return { version: 'unknown', pkgJson: null };
61:  }
62:}
64:/**
65: * Resolve the npm package name for a plugin id by consulting the guild's root package.json.
66: *
67: * Scans all dependencies and runs `derivePluginId()` on each to find the
68: * package whose derived id matches. This correctly handles descriptor
69: * suffixes (-kit, -apparatus, -plugin) that derivePluginId strips.
70: *
71: * When multiple packages derive to the same id (unlikely but possible),
72: * prefers @shardworks-scoped packages over third-party ones.
73: *
74: * Returns null if no matching dependency is found.
75: */
76:export function resolvePackageNameForPluginId(guildRoot: string, pluginId: string): string | null {
77:  const pkgPath = path.join(guildRoot, 'package.json');
78:  let deps: string[] = [];
79:  try {
80:    const pkgJson = JSON.parse(fs.readFileSync(pkgPath, 'utf-8')) as Record<string, unknown>;
81:    deps = Object.keys((pkgJson.dependencies as Record<string, string> | undefined) ?? {});
82:  } catch {
83:    return null;
84:  }
86:  let match: string | null = null;
87:  for (const dep of deps) {
88:    if (derivePluginId(dep) === pluginId) {
89:      // Prefer @shardworks-scoped packages (official namespace)
90:      if (dep.startsWith('@shardworks/')) return dep;
91:      // Keep the first match as fallback
92:      if (!match) match = dep;
93:    }
94:  }
95:  return match;
96:}
98:/**
99: * Resolve the entry point for a guild-installed package.
100: *
101: * Reads the package's exports map to find the ESM entry point.
102: * Returns an absolute path suitable for dynamic import().
103: */
104:export function resolveGuildPackageEntry(guildRoot: string, pkgName: string): string {
105:  const pkgDir = path.join(guildRoot, 'node_modules', pkgName);
106:  const { pkgJson } = readGuildPackageJson(guildRoot, pkgName);
108:  if (pkgJson) {
109:    const exports = pkgJson.exports as Record<string, unknown> | string | undefined;
110:    if (exports) {
111:      if (typeof exports === 'string') return path.join(pkgDir, exports);
112:      const main = (exports as Record<string, unknown>)['.'];
113:      if (typeof main === 'string') return path.join(pkgDir, main);
114:      if (main && typeof main === 'object') {
115:        const importPath = (main as Record<string, string>).import;
116:        if (importPath) return path.join(pkgDir, importPath);
117:      }
118:    }
119:    if (pkgJson.main) return path.join(pkgDir, pkgJson.main as string);
120:  }
122:  return path.join(pkgDir, 'index.js');
123:}

