1:/**
2: * The Loom — session context composition apparatus.
3: *
4: * The Loom owns system prompt assembly. Given a role name, it produces
5: * an AnimaWeave — the composed identity context that The Animator uses
6: * to launch a session. The work prompt (what the anima should do) is
7: * not the Loom's concern; it bypasses the Loom and goes directly to
8: * the Animator.
9: *
10: * The Loom resolves the role's permission grants from guild.json, then
11: * calls the Instrumentarium to resolve the permission-gated tool set.
12: * Tools are returned on the AnimaWeave so the Animator can pass them
13: * to the session provider for MCP server configuration.
14: *
15: * See: docs/specification.md (loom)
16: */
18:import type { Plugin, StartupContext } from '@shardworks/nexus-core';
19:import { guild } from '@shardworks/nexus-core';
20:import type { InstrumentariumApi, ResolvedTool } from '@shardworks/tools-apparatus';
21:import fs from 'node:fs';
22:import path from 'node:path';
24:// ── Public types ──────────────────────────────────────────────────────
26:export interface WeaveRequest {
27:  /**
28:   * The role to weave context for (e.g. 'artificer', 'scribe').
29:   *
30:   * When provided, the Loom resolves role → permissions from guild.json,
31:   * then calls the Instrumentarium to resolve the permission-gated tool set.
32:   * Tools are returned on the AnimaWeave.
33:   *
34:   * When omitted, no tool resolution occurs — the AnimaWeave has no tools.
35:   */
36:  role?: string;
37:}
39:/**
40: * The output of The Loom's weave() — the composed anima identity context.
41: *
42: * Contains the system prompt (produced by the Loom from the anima's
43: * identity layers) and the resolved tool set for the role. The work
44: * prompt is not part of the weave — it goes directly to the Animator.
45: */
46:export interface AnimaWeave {
47:  /**
48:   * The system prompt for the AI process. Composed from guild charter,
49:   * tool instructions, and role instructions. Undefined when no
50:   * composition layers produce content.
51:   */
52:  systemPrompt?: string;
53:  /** The resolved tool set for this role. Undefined when no role is specified or no tools match. */
54:  tools?: ResolvedTool[];
55:  /** Environment variables derived from role identity (e.g. git author/committer). */
56:  environment?: Record<string, string>;
57:}
59:/** The Loom's public API, exposed via `provides`. */
60:export interface LoomApi {
61:  /**
62:   * Weave an anima's session context.
63:   *
64:   * Given a role name, produces an AnimaWeave containing the composed
65:   * system prompt and the resolved tool set. The system prompt is assembled
66:   * from the guild charter, tool instructions (for the resolved tool set),
67:   * and role instructions — in that order.
68:   *
69:   * Tool resolution is active: if a role is provided and the Instrumentarium
70:   * is installed, the Loom resolves role → permissions → tools.
71:   */
72:  weave(request: WeaveRequest): Promise<AnimaWeave>;
73:}
75:// ── Config types ─────────────────────────────────────────────────────
77:/** Role definition in guild.json under the Loom's plugin section. */
78:export interface RoleDefinition {
79:  /** Permission grants in `plugin:level` format. */
80:  permissions: string[];
81:  /**
82:   * When true, permissionless tools are excluded unless the role grants
83:   * `plugin:*` or `*:*` for the tool's plugin. Default: false.
84:   */
85:  strict?: boolean;
86:}
88:/** Loom configuration from guild.json. */
89:export interface LoomConfig {
90:  /** Role definitions keyed by role name. */
91:  roles?: Record<string, RoleDefinition>;
92:}
94:// ── Apparatus factory ─────────────────────────────────────────────────
96:/**
97: * Create the Loom apparatus plugin.
98: *
99: * Returns a Plugin with:
100: * - `requires: ['tools']` — needs the Instrumentarium for tool resolution
101: * - `provides: LoomApi` — the context composition API
102: */
103:export function createLoom(): Plugin {
104:  let config: LoomConfig = {};
105:  let charterContent: string | undefined;
106:  let roleInstructions: Map<string, string> = new Map();
108:  const api: LoomApi = {
109:    async weave(request: WeaveRequest): Promise<AnimaWeave> {
110:      const weave: AnimaWeave = {};
112:      // Resolve tools if a role is provided and has a definition.
113:      if (request.role && config.roles) {
114:        const roleDef = config.roles[request.role];
115:        if (roleDef) {
116:          try {
117:            const instrumentarium = guild().apparatus<InstrumentariumApi>('tools');
118:            weave.tools = instrumentarium.resolve({
119:              permissions: roleDef.permissions,
120:              strict: roleDef.strict,
121:              caller: 'anima',
122:            });
123:          } catch {
124:            // Instrumentarium not installed — no tools.
125:            // This shouldn't happen since we require 'tools', but
126:            // fail gracefully rather than crash the session.
127:          }
128:        }
129:      }
131:      // Derive git identity from role name.
132:      if (request.role) {
133:        const displayName = request.role.charAt(0).toUpperCase() + request.role.slice(1);
134:        weave.environment = {
135:          GIT_AUTHOR_NAME: displayName,
136:          GIT_AUTHOR_EMAIL: `${request.role}@nexus.local`,
137:        };
138:      }
140:      // Compose system prompt from available layers: charter → tool instructions → role instructions.
141:      const layers: string[] = [];
143:      if (charterContent) {
144:        layers.push(charterContent);
145:      }
147:      if (weave.tools && weave.tools.length > 0) {
148:        for (const resolvedTool of weave.tools) {
149:          const instructions = resolvedTool.definition.instructions;
150:          if (instructions) {
151:            layers.push(`## Tool: ${resolvedTool.definition.name}\n\n${instructions}`);
152:          }
153:        }
154:      }
156:      if (request.role && roleInstructions.has(request.role)) {
157:        layers.push(roleInstructions.get(request.role)!);
158:      }
160:      if (layers.length > 0) {
161:        weave.systemPrompt = layers.join('\n\n');
162:      }
164:      return weave;
165:    },
166:  };
168:  return {
169:    apparatus: {
170:      requires: ['tools'],
171:      provides: api,
173:      start(_ctx: StartupContext): void {
174:        const g = guild();
175:        config = g.guildConfig().loom ?? {};
176:        const home = g.home;
178:        // Read charter content at startup and cache it.
179:        charterContent = undefined;
180:        const charterFilePath = path.join(home, 'charter.md');
181:        try {
182:          charterContent = fs.readFileSync(charterFilePath, 'utf-8');
183:        } catch (err: unknown) {
184:          if ((err as NodeJS.ErrnoException).code !== 'ENOENT') throw err;
185:          // No charter.md — check for charter/ directory.
186:          const charterDir = path.join(home, 'charter');
187:          try {
188:            const stat = fs.statSync(charterDir);
189:            if (stat.isDirectory()) {
190:              const mdFiles = fs.readdirSync(charterDir)
191:                .filter(f => f.endsWith('.md'))
192:                .sort();
193:              if (mdFiles.length > 0) {
194:                charterContent = mdFiles
195:                  .map(f => fs.readFileSync(path.join(charterDir, f), 'utf-8'))
196:                  .join('\n\n');
197:              }
198:            }
199:          } catch {
200:            // No charter/ directory either — silently omit.
201:          }
202:        }
204:        // Read role instruction files at startup for all configured roles.
205:        roleInstructions = new Map();
206:        if (config.roles) {
207:          for (const roleName of Object.keys(config.roles)) {
208:            const rolePath = path.join(home, 'roles', `${roleName}.md`);
209:            try {
210:              const content = fs.readFileSync(rolePath, 'utf-8');
211:              if (content) {
212:                roleInstructions.set(roleName, content);
213:              }
214:            } catch {
215:              // File doesn't exist — silently omit.
216:            }
217:          }
218:        }
219:      },
220:    },
221:  };
222:}

